165→    @GetResource(path = "/syncSpaceApp", requiredPermission = false)
166→    @Operation(summary = "刷一遍子应用空间站")
167→    public void syncSpaceApp() {
168→
169→        List<SpaceEntity> spaces = spaceService.list();
170→
171→        //刷用户
172→        Set<Long> userIds = spaces.stream()
173→                .flatMap(space -> {
174→                    Set<Long> ids = new HashSet<>();
175→                    if (space.getOwner() != null) {
176→                        ids.add(space.getOwner());
177→                    }
178→                    if (space.getCreatedBy() != null) {
179→                        ids.add(space.getCreatedBy());
180→                    }
181→                    if (space.getUpdatedBy() != null) {
182→                        ids.add(space.getUpdatedBy());
183→                    }
184→                    return ids.stream();
185→                })
186→                .collect(Collectors.toSet());
187→
188→        for (Long userId : userIds) {
189→            UserSimpleInfoVo user = apitableGrpcClientService.getUserById(userId);
190→            CreateUserResponse res = affineHttpClientService.createUser(new CreateUserRequest(user.getEmail(), user.getNickName(), "dev"), 1861372503096078339L);// 1861372503096078339测试服的test用户
191→            log.info("create affine user , email: {}, name: {}, response: {}", user.getEmail(), user.getNickName(), res);
192→        }
193→
194→        //刷空间站
195→        for (SpaceEntity space : spaces) {
196→            List<SpaceAppRelEntity> spaceAppRelEntities = spaceAppRelService.listBySpaceId(space.getSpaceId());
197→            Set<Integer> appTypeSet = spaceAppRelEntities.stream().map(SpaceAppRelEntity::getAppType).collect(Collectors.toSet());
198→            if(!appTypeSet.contains(SpaceAppTypeEnum.AFFINE.getValue())) {
199→                String afResult = affineHttpClientService.createWorkspace(new CreateWorkspaceRequest(space.getName(),"aio"), space.getOwner());
200→                log.info("affine workspace {} created by user: {} , result: {}", space.getName(), space.getOwner(), afResult);
201→                SpaceAppRelEntity entity = SpaceAppRelEntity.builder()
202→                        .spaceId(space.getSpaceId())
203→                        .appSpaceId(afResult)
204→                        .appType(SpaceAppTypeEnum.AFFINE.getValue())
205→                        .createdAt(space.getCreatedAt())
206→                        .createdBy(space.getCreatedBy())
207→                        .build();
208→                spaceAppRelService.save(entity);
209→            }
210→        }
211→
212→    }
